#include <bits/stdc++.h>
using namespace std;
int m,q;
string s;
int dfs(int st,int e,int x)
{
    if(s[st]>='0'&&s[st]<='9')
    {
        int num=0;
        for(int i=st;i<=e;i++) num=num*10+s[i]-'0';
        return num;
    }
    int t=0,num,t2;
    for(int i=st+2;i<=e;i++)
    {
        if(s[i]=='>'||s[i]=='<') t--;
        else if(s[i]=='?')
        {
            t++;
            if(t==1)
            {
                num=dfs(st+2,i-1,x);
                t2=i;
                break;
            }
        }
    }
    int op;
    if(s[st+1]=='>')
    {
        if(x>num) op=1;
        else op=2;
    }
    else
    {
        if(num>x) op=1;
        else op=2;
    }
    for(int i=t2+1;i<=e;i++)
    {
        if(s[i]=='>'||s[i]=='<') t--;
        else if(s[i]==':')
        {
            t++;
            if(t==2) t=i;
        }
    }
    if(op==1) return dfs(t2+1,t-1,x);
    return dfs(t+1,e,x);
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>m>>q>>s;
    while(q--)
    {
        int x;
        cin>>x;
        cout<<dfs(0,s.size()-1,x)<<'\n';
    }
    return 0;
}
